n = len(grid)
    if k <= 0:
        return []
    if k == 1:
        mn = grid[0][0]
        for row in grid:
            for v in row:
                if v < mn:
                    mn = v
        return [mn]

    # Precompute neighbors for each cell
    neighbors = {}
    for i in range(n):
        for j in range(n):
            ns = []
            if i > 0:
                ns.append((i - 1, j))
            if i + 1 < n:
                ns.append((i + 1, j))
            if j > 0:
                ns.append((i, j - 1))
            if j + 1 < n:
                ns.append((i, j + 1))
            neighbors[(i, j)] = ns

    # DP over paths: dp[t][cell] = lexicographically minimal path values of length t+1
    # ending at cell. We keep only current layer.
    cur = {}
    for i in range(n):
        for j in range(n):
            cur[(i, j)] = [grid[i][j]]

    for _ in range(1, k):
        nxt = {}
        for (i, j), path in cur.items():
            for ni, nj in neighbors[(i, j)]:
                cand = path + [grid[ni][nj]]
                key = (ni, nj)
                if key not in nxt or cand < nxt[key]:
                    nxt[key] = cand
        cur = nxt

    best = None
    for path in cur.values():
        if best is None or path < best:
            best = path
    return best
